import { z } from "zod";
import { jsonObjectSchema, jsonValueSchema } from "./json-schema";
import { sharedErrorCodeSchema } from "./error-codes";

const nonEmptyStringSchema = z.string().trim().min(1);
const nullableStringSchema = z.string().nullable();
const nullishStringSchema = z.string().nullish();
const nonNegativeIntSchema = z.number().int().nonnegative();
const positiveIntSchema = z.number().int().positive();
const paginationLimitSchema = z.number().int().positive().max(1000);
export const apiErrorCodeSchema = z.union([
  sharedErrorCodeSchema,
  z.string().trim().regex(/^[A-Z][A-Z0-9_]*$/),
]);

export const offsetPaginationMetaSchema = z.object({
  mode: z.literal("offset"),
  page: positiveIntSchema,
  pageSize: paginationLimitSchema,
  limit: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  total: nonNegativeIntSchema,
  totalPages: positiveIntSchema,
  hasNextPage: z.boolean(),
  hasPreviousPage: z.boolean(),
});

export const cursorPaginationMetaSchema = z.object({
  mode: z.literal("cursor"),
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema.optional(),
  nextCursor: nullableStringSchema,
  hasMore: z.boolean(),
  total: nonNegativeIntSchema,
});

export const hybridPaginationMetaSchema = z.object({
  mode: z.literal("hybrid"),
  page: positiveIntSchema,
  pageSize: paginationLimitSchema,
  limit: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  total: nonNegativeIntSchema,
  totalPages: positiveIntSchema,
  nextCursor: nullableStringSchema,
  hasNextPage: z.boolean(),
  hasPreviousPage: z.boolean(),
});

export const apiPaginationMetaSchema = z.discriminatedUnion("mode", [
  offsetPaginationMetaSchema,
  cursorPaginationMetaSchema,
  hybridPaginationMetaSchema,
]);

export const importRecordSchema = z.object({
  id: nonEmptyStringSchema,
  name: nonEmptyStringSchema,
  filename: nonEmptyStringSchema,
  createdAt: nonEmptyStringSchema,
  isDeleted: z.boolean(),
  createdBy: nullishStringSchema,
});

export const importListItemSchema = importRecordSchema.extend({
  rowCount: nonNegativeIntSchema,
});

export const importsListResponseSchema = z.object({
  imports: z.array(importListItemSchema),
  pagination: cursorPaginationMetaSchema,
});

export const importDataRowSchema = z.object({
  id: nonEmptyStringSchema,
  importId: nonEmptyStringSchema,
  jsonDataJsonb: jsonObjectSchema,
});

export const importDataPageResponseSchema = z.object({
  rows: z.array(importDataRowSchema),
  headers: z.array(nonEmptyStringSchema),
  total: nonNegativeIntSchema,
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema.optional(),
  offset: nonNegativeIntSchema,
  nextCursor: nullableStringSchema,
  pagination: hybridPaginationMetaSchema,
});

const searchResultRowSchema = jsonObjectSchema;

export const searchGlobalResponseSchema = z.object({
  columns: z.array(nonEmptyStringSchema),
  rows: z.array(searchResultRowSchema),
  results: z.array(searchResultRowSchema),
  total: nonNegativeIntSchema,
  totalIsApproximate: z.boolean().optional(),
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  pagination: offsetPaginationMetaSchema,
});

export const advancedSearchResponseSchema = z.object({
  results: z.array(searchResultRowSchema),
  headers: z.array(nonEmptyStringSchema),
  total: nonNegativeIntSchema,
  page: positiveIntSchema,
  limit: paginationLimitSchema,
  pageSize: paginationLimitSchema,
  offset: nonNegativeIntSchema,
  pagination: offsetPaginationMetaSchema,
});

export const auditLogRecordSchema = z.object({
  id: nonEmptyStringSchema,
  action: nonEmptyStringSchema,
  performedBy: nonEmptyStringSchema,
  requestId: nullishStringSchema,
  targetUser: nullishStringSchema,
  targetResource: nullishStringSchema,
  details: nullishStringSchema,
  timestamp: nonEmptyStringSchema,
});

export const auditLogsResponseSchema = z.object({
  logs: z.array(auditLogRecordSchema),
  pagination: offsetPaginationMetaSchema,
});

export const apiErrorDetailsSchema = z.object({
  code: apiErrorCodeSchema.optional(),
  message: z.string(),
  details: jsonValueSchema.optional(),
  requestId: z.string().optional(),
}).passthrough();

export const apiErrorPayloadSchema = z.object({
  ok: z.literal(false).optional(),
  message: z.string(),
  requestId: z.string().optional(),
  code: apiErrorCodeSchema.optional(),
  error: apiErrorDetailsSchema.optional(),
}).passthrough();

export const deleteImportResponseSchema = z.object({
  ok: z.literal(true).optional(),
  success: z.boolean(),
});

export const settingOptionSchema = z.object({
  value: z.string(),
  label: z.string(),
});

export const settingPermissionSchema = z.object({
  canView: z.boolean(),
  canEdit: z.boolean(),
});

export const settingItemSchema = z.object({
  key: nonEmptyStringSchema,
  label: nonEmptyStringSchema,
  description: z.string().nullable(),
  type: z.enum(["text", "number", "boolean", "select", "timestamp"]),
  value: z.string(),
  defaultValue: z.string().nullable(),
  isCritical: z.boolean(),
  updatedAt: z.string().nullable(),
  permission: settingPermissionSchema,
  options: z.array(settingOptionSchema),
});

export const settingCategorySchema = z.object({
  id: nonEmptyStringSchema,
  name: nonEmptyStringSchema,
  description: z.string().nullable(),
  settings: z.array(settingItemSchema),
});

export const settingsResponseSchema = z.object({
  categories: z.array(settingCategorySchema),
});

export const settingsUpdateResponseSchema = z.object({
  ok: z.literal(true).optional(),
  success: z.boolean(),
  status: z.enum(["updated", "unchanged"]),
  message: z.string(),
  setting: settingItemSchema.nullable(),
});

export const tabVisibilityResponseSchema = z.object({
  role: nonEmptyStringSchema,
  tabs: z.record(z.boolean()),
});

export type ImportsListResponse = z.infer<typeof importsListResponseSchema>;
export type ImportDataPageResponse = z.infer<typeof importDataPageResponseSchema>;
export type SearchGlobalResponse = z.infer<typeof searchGlobalResponseSchema>;
export type AdvancedSearchResponse = z.infer<typeof advancedSearchResponseSchema>;
export type AuditLogsResponse = z.infer<typeof auditLogsResponseSchema>;
export type ApiErrorPayload = z.infer<typeof apiErrorPayloadSchema>;
export type SettingsResponse = z.infer<typeof settingsResponseSchema>;
export type SettingsUpdateResponse = z.infer<typeof settingsUpdateResponseSchema>;
export type TabVisibilityResponse = z.infer<typeof tabVisibilityResponseSchema>;
export type ApiPaginationMeta = z.infer<typeof apiPaginationMetaSchema>;
export type NormalizedApiPaginationMeta = {
  mode: ApiPaginationMeta["mode"];
  page: number | null;
  pageSize: number;
  limit: number;
  offset: number | null;
  total: number;
  totalPages: number | null;
  nextCursor: string | null;
  hasNextPage: boolean;
  hasPreviousPage: boolean;
  hasMore: boolean;
};

export function normalizeApiPaginationMeta(
  pagination: ApiPaginationMeta,
): NormalizedApiPaginationMeta {
  if (pagination.mode === "cursor") {
    return {
      mode: pagination.mode,
      page: null,
      pageSize: pagination.pageSize ?? pagination.limit,
      limit: pagination.limit,
      offset: null,
      total: pagination.total,
      totalPages: null,
      nextCursor: pagination.nextCursor,
      hasNextPage: pagination.hasMore,
      hasPreviousPage: false,
      hasMore: pagination.hasMore,
    };
  }

  const hasMore = pagination.mode === "hybrid"
    ? pagination.hasNextPage || pagination.nextCursor !== null
    : pagination.hasNextPage;

  return {
    mode: pagination.mode,
    page: pagination.page,
    pageSize: pagination.pageSize,
    limit: pagination.limit,
    offset: pagination.offset,
    total: pagination.total,
    totalPages: pagination.totalPages,
    nextCursor: pagination.mode === "hybrid" ? pagination.nextCursor : null,
    hasNextPage: pagination.hasNextPage,
    hasPreviousPage: pagination.hasPreviousPage,
    hasMore,
  };
}

import { z } from "zod";

export type JsonPrimitive = string | number | boolean | null;
export type JsonValue = JsonPrimitive | JsonObject | JsonValue[];
export type JsonObject = { [key: string]: JsonValue };

const jsonPrimitiveSchema = z.union([
  z.string(),
  z.number().finite(),
  z.boolean(),
  z.null(),
]);

export const jsonValueSchema: z.ZodType<JsonValue> = z.lazy(() =>
  z.union([
    jsonPrimitiveSchema,
    z.array(jsonValueSchema),
    z.record(jsonValueSchema),
  ]),
);

export const jsonObjectSchema: z.ZodType<JsonObject> = z.lazy(() =>
  z.record(jsonValueSchema),
);

import type { Response } from "express";
import { z } from "zod";
import type { AuthenticatedRequest } from "../auth/guards";
import { badRequest, notFound } from "../http/errors";
import { runWithRequestDeadline } from "../http/request-deadline";
import { readInteger, readNonEmptyString } from "../http/validation";
import {
  cleanupPreparedMultipartImportUpload,
  type PreparedMultipartImportUpload,
} from "../routes/imports-multipart-utils";
import type { ImportDataColumnFilter, ImportsService } from "../services/imports.service";

type RuntimeSettings = {
  viewerRowsPerPage: number;
};

type CreateImportsControllerDeps = {
  importsService: ImportsService;
  getRuntimeSettingsCached: () => Promise<RuntimeSettings>;
  isDbProtected: () => boolean;
  analysisRequestTimeoutMs?: number | undefined;
};

export type ImportsController = ReturnType<typeof createImportsController>;

const viewerColumnFilterSchema = z.object({
  column: z.string().trim().min(1).max(120),
  operator: z.enum(["contains", "equals", "startsWith", "endsWith", "notEquals"]),
  value: z.string().trim().min(1).max(500),
});

const viewerColumnFiltersSchema = z.array(viewerColumnFilterSchema).max(10);

function buildImportMutationSuccessPayload<T extends Record<string, unknown>>(payload?: T) {
  return {
    ok: true as const,
    success: true as const,
    ...(payload ?? {}),
  };
}

function parseViewerColumnFiltersQuery(value: unknown): ImportDataColumnFilter[] {
  const normalized = readNonEmptyString(value);
  if (!normalized) {
    return [];
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(normalized);
  } catch {
    throw badRequest("Invalid viewer column filters.");
  }

  const result = viewerColumnFiltersSchema.safeParse(parsed);
  if (!result.success) {
    throw badRequest("Invalid viewer column filters.");
  }

  return result.data;
}

export function createImportsController(deps: CreateImportsControllerDeps) {
  const {
    importsService,
    getRuntimeSettingsCached,
    isDbProtected,
    analysisRequestTimeoutMs,
  } = deps;

  const listDataRows = async (req: AuthenticatedRequest, res: Response) => {
    const importId = readNonEmptyString(req.query.importId);
    const pageSize = readInteger(req.query.pageSize ?? req.query.limit, 10);
    const page = Math.max(1, readInteger(req.query.page, 1));
    const offsetQuery = readNonEmptyString(req.query.offset);
    const offset = offsetQuery ? readInteger(req.query.offset, 0) : (page - 1) * pageSize;
    const search = String(req.query.q || "").trim();

    if (!importId) {
      throw badRequest("importId is required");
    }

    const result = await importsService.searchImportRows({
      importId,
      search: search || null,
      limit: pageSize,
      offset,
    });

    return res.json(result);
  };

  const listImports = async (_req: AuthenticatedRequest, res: Response) => {
    const cursor = readNonEmptyString(_req.query.cursor);
    const pageSize = readInteger(_req.query.pageSize ?? _req.query.limit, 100);
    const search = readNonEmptyString(_req.query.search);
    const createdOn = readNonEmptyString(_req.query.createdOn);

    try {
      const result = await importsService.listImports({
        cursor: cursor || null,
        limit: pageSize,
        search: search || null,
        createdOn: createdOn || null,
      });
      return res.json({
        imports: result.items,
        pagination: {
          mode: "cursor" as const,
          limit: result.limit,
          pageSize: result.limit,
          nextCursor: result.nextCursor,
          hasMore: result.nextCursor !== null,
          total: result.total,
        },
      });
    } catch (error) {
      if (error instanceof Error && /invalid imports cursor/i.test(error.message)) {
        throw badRequest("Invalid imports cursor.");
      }
      throw error;
    }
  };

  const createImport = async (req: AuthenticatedRequest, res: Response) => {
    const multipartImportUpload = (res.locals as {
      multipartImportUpload?: PreparedMultipartImportUpload;
    }).multipartImportUpload;

    try {
      if (multipartImportUpload?.kind === "csv-file") {
        const body = req.body && typeof req.body === "object"
          ? req.body as Record<string, unknown>
          : {};
        const name = String(body.name ?? "");
        const filename = String(body.filename ?? multipartImportUpload.filename ?? "");

        const importRecord = await importsService.createImportFromCsvFile({
          name,
          filename,
          filePath: multipartImportUpload.filePath,
          createdBy: req.user?.username,
        });

        return res.json(importRecord);
      }

      const { name, filename, dataRows } = importsService.parseCreateImportBody(req.body);

      if (!Array.isArray(dataRows) || dataRows.length === 0) {
        throw badRequest("No data rows provided");
      }

      const importRecord = await importsService.createImport({
        name,
        filename,
        dataRows,
        createdBy: req.user?.username,
      });

      return res.json(importRecord);
    } finally {
      await cleanupPreparedMultipartImportUpload(multipartImportUpload);
      delete (res.locals as { multipartImportUpload?: PreparedMultipartImportUpload }).multipartImportUpload;
    }
  };

  const getImport = async (req: AuthenticatedRequest, res: Response) => {
    const importId = readNonEmptyString(req.params.id);
    if (!importId) {
      throw notFound("Import not found");
    }

    const details = await importsService.getImportDetails(importId);
    if (!details) {
      throw notFound("Import not found");
    }

    return res.json(details);
  };

  const getImportDataPage = async (req: AuthenticatedRequest, res: Response) => {
    const runtimeSettings = await getRuntimeSettingsCached();
    const importId = readNonEmptyString(req.params.id);
    const page = Math.max(1, readInteger(req.query.page, 1));
    const cursor = readNonEmptyString(req.query.cursor);
    const requestedPageSize = readInteger(
      req.query.pageSize ?? req.query.limit,
      runtimeSettings.viewerRowsPerPage,
    );
    const search = String(req.query.search || "").trim();
    const columnFilters = parseViewerColumnFiltersQuery(req.query.columnFilters);

    if (!importId) {
      throw badRequest("importId is required");
    }

    try {
      const result = await importsService.getImportDataPage({
        importId,
        page,
        cursor: cursor || null,
        requestedLimit: requestedPageSize,
        viewerRowsPerPage: runtimeSettings.viewerRowsPerPage,
        isDbProtected: isDbProtected(),
        search,
        columnFilters,
      });

      return res.json(result);
    } catch (error) {
      if (error instanceof Error && /invalid import data cursor/i.test(error.message)) {
        throw badRequest("Invalid import data cursor.");
      }
      throw error;
    }
  };

  const analyzeImport = async (req: AuthenticatedRequest, res: Response) => {
    const outcome = await runWithRequestDeadline(
      res,
      {
        timeoutMs: analysisRequestTimeoutMs ?? 45_000,
        operationName: "import-analysis",
        timeoutMessage:
          "Import analysis is taking longer than expected. Please retry in a moment.",
      },
      (signal) => importsService.analyzeImport(req.params.id, signal),
    );
    if (outcome.timedOut) {
      return;
    }

    const analysis = outcome.value;
    if (!analysis) {
      throw notFound("Import not found");
    }

    return res.json(analysis);
  };

  const analyzeAll = async (_req: AuthenticatedRequest, res: Response) => {
    const outcome = await runWithRequestDeadline(
      res,
      {
        timeoutMs: analysisRequestTimeoutMs ?? 45_000,
        operationName: "imports-analysis-all",
        timeoutMessage:
          "Import analysis is taking longer than expected. Please retry in a moment.",
      },
      (signal) => importsService.analyzeAll(signal),
    );
    if (outcome.timedOut) {
      return;
    }

    return res.json(outcome.value);
  };

  const renameImport = async (req: AuthenticatedRequest, res: Response) => {
    const { name } = importsService.parseRenameBody(req.body);
    const updated = await importsService.renameImport(req.params.id, name, req.user?.username);
    if (!updated) {
      throw notFound("Import not found");
    }

    return res.json(updated);
  };

  const deleteImport = async (req: AuthenticatedRequest, res: Response) => {
    const deleted = await importsService.deleteImport(req.params.id, req.user?.username);
    if (!deleted) {
      throw notFound("Import not found");
    }

    return res.json(buildImportMutationSuccessPayload());
  };

  return {
    listDataRows,
    listImports,
    createImport,
    getImport,
    getImportDataPage,
    analyzeImport,
    analyzeAll,
    renameImport,
    deleteImport,
  };
}

export class HttpError extends Error {
  readonly statusCode: number;
  readonly code?: string | undefined;
  readonly details?: unknown;
  readonly expose: boolean;

  constructor(
    statusCode: number,
    message: string,
    options?: { code?: string | undefined; details?: unknown; expose?: boolean | undefined },
  ) {
    super(message);
    this.name = "HttpError";
    this.statusCode = statusCode;
    this.code = options?.code;
    this.details = options?.details;
    this.expose = options?.expose ?? statusCode < 500;
  }
}

export function badRequest(message: string, code?: string, details?: unknown) {
  return new HttpError(400, message, { code, details });
}

export function unauthorized(message = "Authentication required.", code?: string) {
  return new HttpError(401, message, { code });
}

export function forbidden(message = "Insufficient permissions.", code?: string) {
  return new HttpError(403, message, { code });
}

export function notFound(message = "Resource not found.", code?: string) {
  return new HttpError(404, message, { code });
}

export function conflict(message: string, code?: string) {
  return new HttpError(409, message, { code });
}

import type { Response } from "express";
import { ERROR_CODES } from "../../shared/error-codes";
import { logger } from "../lib/logger";

type RequestDeadlineOptions = {
  timeoutMs: number;
  operationName: string;
  timeoutMessage: string;
};

export type RequestDeadlineResult<T> =
  | { timedOut: true }
  | { timedOut: false; value: T };

export async function runWithRequestDeadline<T>(
  res: Response,
  options: RequestDeadlineOptions,
  operation: (signal: AbortSignal) => Promise<T>,
): Promise<RequestDeadlineResult<T>> {
  const timeoutMs = Number.isFinite(options.timeoutMs)
    ? Math.max(1, Math.trunc(options.timeoutMs))
    : 0;

  if (timeoutMs <= 0) {
    const controller = new AbortController();
    return {
      timedOut: false,
      value: await operation(controller.signal),
    };
  }

  const controller = new AbortController();
  let settled = false;
  let timer: NodeJS.Timeout | null = null;

  const finalize = () => {
    settled = true;
    if (timer) {
      clearTimeout(timer);
      timer = null;
    }
  };

  const operationPromise = Promise.resolve()
    .then(() => operation(controller.signal))
    .then<RequestDeadlineResult<T>>((value) => {
      if (settled) {
        return { timedOut: true };
      }
      finalize();
      return {
        timedOut: false,
        value,
      };
    })
    .catch<RequestDeadlineResult<T>>((error: unknown) => {
      if (settled) {
        logger.warn("Request operation settled after timeout response", {
          operationName: options.operationName,
          error,
        });
        return { timedOut: true };
      }
      finalize();
      throw error;
    });

  const timeoutPromise = new Promise<RequestDeadlineResult<T>>((resolve) => {
    timer = setTimeout(() => {
      if (settled) {
        resolve({ timedOut: true });
        return;
      }

      finalize();
      controller.abort();
      logger.warn("HTTP request exceeded deadline", {
        operationName: options.operationName,
        timeoutMs,
      });

      if (!res.headersSent) {
        res.status(504).json({
          ok: false,
          message: options.timeoutMessage,
          error: {
            code: ERROR_CODES.REQUEST_TIMEOUT,
            message: options.timeoutMessage,
            details: {
              operation: options.operationName,
              timeoutMs,
            },
          },
        });
      }

      resolve({ timedOut: true });
    }, timeoutMs);
    timer.unref?.();
  });

  return Promise.race([operationPromise, timeoutPromise]);
}

