    `Invalid runtime environment configuration: ${result.error.issues
      .map(formatRuntimeEnvIssue)
      .join("; ")}`,
  );
}

import path from "node:path";

export function isPathInsideDirectory(params: {
  parentDir: string;
  candidatePath: string;
}): boolean {
  const parentDir = path.resolve(params.parentDir);
  const candidatePath = path.resolve(params.candidatePath);
  const relativePath = path.relative(parentDir, candidatePath);

  return relativePath === "" || (
    Boolean(relativePath)
    && !relativePath.startsWith("..")
    && !path.isAbsolute(relativePath)
  );
}

export function resolveUploadsRootDir(params: {
  projectRoot?: string;
  uploadsDirName?: string;
} = {}): string {
  const projectRoot = path.resolve(params.projectRoot || process.cwd());
  const uploadsDirName = String(params.uploadsDirName || "uploads").trim();
  if (!uploadsDirName) {
    throw new Error("Uploads root directory name must not be empty.");
  }

  const uploadsRootDir = path.resolve(projectRoot, uploadsDirName);
  if (
    uploadsRootDir === projectRoot
    || !isPathInsideDirectory({ parentDir: projectRoot, candidatePath: uploadsRootDir })
  ) {
    throw new Error("Uploads root must resolve inside the project workspace.");
  }

  return uploadsRootDir;
}

const BODY_LIMIT_UNITS: Record<string, number> = {
  b: 1,
  kb: 1024,
  k: 1024,
  mb: 1024 * 1024,
  m: 1024 * 1024,
  gb: 1024 * 1024 * 1024,
  g: 1024 * 1024 * 1024,
};

export const DEFAULT_IMPORT_BODY_LIMIT = "96mb";
export const DEFAULT_IMPORT_UPLOAD_LIMIT_BYTES = 96 * 1024 * 1024;

export function parseBodyLimitToBytes(
  rawValue: string | null | undefined,
  fallbackBytes: number = DEFAULT_IMPORT_UPLOAD_LIMIT_BYTES,
) {
  const normalized = String(rawValue || "").trim().toLowerCase();
  if (!normalized) {
    return fallbackBytes;
  }

  const match = normalized.match(/^(\d+(?:\.\d+)?)\s*(b|kb|k|mb|m|gb|g)?$/i);
  if (!match) {
    return fallbackBytes;
  }

  const numericValue = Number(match[1]);
  const multiplier = BODY_LIMIT_UNITS[String(match[2] || "b").toLowerCase()] || 1;
  const resolvedBytes = Math.floor(numericValue * multiplier);

  if (!Number.isFinite(resolvedBytes) || resolvedBytes < 1) {
    return fallbackBytes;
  }

  return resolvedBytes;
}

