import fs from "node:fs";
import readline from "node:readline";
import {
  createUploadFileAccessError,
  createUploadFileTooLargeError,
  isFileAccessError,
  validateUploadFileSize,
} from "./import-upload-file-utils";
import type { ImportRow, ParsedImportUploadResult } from "./import-upload-types";

export const DEFAULT_IMPORT_CSV_MAX_ROWS = 100_000;
export const DEFAULT_IMPORT_CSV_MAX_MATERIALIZED_ROWS = 5_000;

type ParseCsvOptions = {
  maxRows?: number;
  maxBytes?: number;
  maxMaterializedRows?: number;
};

type ReadlineErrorEmitter = {
  once(event: "error", listener: (error: Error) => void): unknown;
  off(event: "error", listener: (error: Error) => void): unknown;
};

export type CsvFileInspectionResult = {
  headers: string[];
  rowCount: number;
  error?: string;
};

function resolveCsvMaxRows(options?: ParseCsvOptions) {
  const value = options?.maxRows;
  if (value == null || !Number.isFinite(value)) {
    return DEFAULT_IMPORT_CSV_MAX_ROWS;
  }

  return Math.max(1, Math.trunc(value));
}

function createCsvRowLimitError(maxRows: number): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: `CSV import exceeds the configured row limit of ${maxRows.toLocaleString("en-US")} rows. Split the file into smaller uploads.`,
  };
}

function createCsvMaterializationLimitError(maxRows: number): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: `CSV import exceeds the in-memory materialization safety limit of ${maxRows.toLocaleString("en-US")} rows. Use the staged multipart import flow for larger files.`,
  };
}

function resolveCsvMaterializedMaxRows(options?: ParseCsvOptions) {
  const configuredMaxRows = resolveCsvMaxRows(options);
  const requestedMaterializedLimit = options?.maxMaterializedRows;
  const materializedLimit = requestedMaterializedLimit == null || !Number.isFinite(requestedMaterializedLimit)
    ? DEFAULT_IMPORT_CSV_MAX_MATERIALIZED_ROWS
    : Math.max(1, Math.trunc(requestedMaterializedLimit));

  return Math.min(configuredMaxRows, materializedLimit);
}

function parseCsvLine(line: string): string[] {
  const result: string[] = [];
  let current = "";
  let inQuotes = false;

  for (let index = 0; index < line.length; index += 1) {
    const char = line[index];
    if (char === '"') {
      if (inQuotes && line[index + 1] === '"') {
        current += '"';
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
    } else if (char === "," && !inQuotes) {
      result.push(current.trim());
      current = "";
    } else {
      current += char;
    }
  }

  result.push(current.trim());
  return result;
}

function findHeaderLine(lines: string[]) {
  let headerLineIndex = 0;
  while (headerLineIndex < lines.length && !lines[headerLineIndex].trim()) {
    headerLineIndex += 1;
  }
  return headerLineIndex;
}

function toParsedCsvRow(headers: string[], values: string[]): ImportRow {
  const row: ImportRow = {};
  headers.forEach((header, headerIndex) => {
    row[header] = values[headerIndex] || "";
  });
  return row;
}

async function walkCsvFile(
  filePath: string,
  options: ParseCsvOptions | undefined,
  onRow?: (row: ImportRow) => Promise<void> | void,
): Promise<CsvFileInspectionResult> {
  const sizeValidation = await validateUploadFileSize(filePath, options?.maxBytes);
  if (sizeValidation) {
    const sizeValidationError = sizeValidation.error
      ?? createUploadFileTooLargeError().error
      ?? "The selected file is too large to import. Please split it into smaller files and try again.";
    return {
      headers: [],
      rowCount: 0,
      error: sizeValidationError,
    };
  }

  const maxRows = resolveCsvMaxRows(options);
  const stream = fs.createReadStream(filePath, { encoding: "utf8" });
  const lineReader = readline.createInterface({
    input: stream,
    crlfDelay: Infinity,
  });
  const lineReaderErrorEmitter = lineReader as unknown as ReadlineErrorEmitter;
  let pendingReaderError: unknown = null;

  const closeLineReaderSafely = () => {
    try {
      lineReader.close();
    } catch (error) {
      if (!pendingReaderError) {
        pendingReaderError = error;
      }
    }
  };

  const destroyStreamSafely = () => {
    try {
      stream.destroy();
    } catch (error) {
      if (!pendingReaderError) {
        pendingReaderError = error;
      }
    }
  };

  const handleReaderError = (error: Error) => {
    if (!pendingReaderError) {
      pendingReaderError = error;
    }
    closeLineReaderSafely();
    destroyStreamSafely();
  };
  stream.once("error", handleReaderError);
  lineReaderErrorEmitter.once("error", handleReaderError);

  let headers: string[] = [];
  let headerResolved = false;
  let rowCount = 0;
  let rowLimitExceeded = false;

  try {
    for await (const rawLine of lineReader) {
      const line = String(rawLine ?? "");
      const normalizedLine = headerResolved ? line : line.replace(/^\ufeff/, "");
      if (!normalizedLine.trim()) {
        continue;
      }

      if (!headerResolved) {
        headers = parseCsvLine(normalizedLine);
        headerResolved = true;
        continue;
      }

      const row = toParsedCsvRow(headers, parseCsvLine(normalizedLine));
      if (Object.values(row).some((value) => value !== "")) {
        if (rowCount >= maxRows) {
          rowLimitExceeded = true;
          closeLineReaderSafely();
          destroyStreamSafely();
          break;
        }

        rowCount += 1;
        await onRow?.(row);
      }
    }

    if (pendingReaderError) {
      throw pendingReaderError;
    }
  } catch (error) {
    if (isFileAccessError(error)) {
      const fileAccessError = createUploadFileAccessError().error ?? "Cannot access the uploaded file. Please try again.";
      return {
        headers: [],
        rowCount: 0,
        error: fileAccessError,
      };
    }
    throw error;
  } finally {
    stream.off("error", handleReaderError);
    lineReaderErrorEmitter.off("error", handleReaderError);
    closeLineReaderSafely();
    destroyStreamSafely();
  }

  if (!headerResolved || headers.length === 0) {
    return { headers: [], rowCount: 0, error: "CSV file is empty." };
  }

  if (rowLimitExceeded) {
    const rowLimitError = createCsvRowLimitError(maxRows).error
      ?? `CSV import exceeds the configured row limit of ${maxRows.toLocaleString("en-US")} rows. Split the file into smaller uploads.`;
    return { headers: [], rowCount: rowCount, error: rowLimitError };
  }

  return { headers, rowCount };
}

export function parseCsvBuffer(buffer: Buffer, options?: ParseCsvOptions): ParsedImportUploadResult {
  if (Number.isFinite(options?.maxBytes) && (options?.maxBytes as number) > 0 && buffer.length > (options?.maxBytes as number)) {
    return createUploadFileTooLargeError();
  }

  const maxRows = resolveCsvMaxRows(options);
  const materializedMaxRows = resolveCsvMaterializedMaxRows(options);
  const text = buffer.toString("utf8").replace(/^\ufeff/, "");
  const lines = text.split(/\r?\n/);

  if (lines.length === 0) {
    return { headers: [], rows: [], error: "CSV file is empty." };
  }

  const headerLineIndex = findHeaderLine(lines);
  if (headerLineIndex >= lines.length) {
    return { headers: [], rows: [], error: "CSV file is empty." };
  }

  const headers = parseCsvLine(lines[headerLineIndex]);
  const rows: ImportRow[] = [];

  for (let index = headerLineIndex + 1; index < lines.length; index += 1) {
    const line = lines[index];
    if (!line.trim()) continue;

    const row = toParsedCsvRow(headers, parseCsvLine(line));
    if (Object.values(row).some((value) => value !== "")) {
      if (rows.length >= maxRows) {
        return createCsvRowLimitError(maxRows);
      }
      if (rows.length >= materializedMaxRows) {
        return createCsvMaterializationLimitError(materializedMaxRows);
      }
      rows.push(row);
    }
  }

  return { headers, rows };
}

export async function inspectCsvFile(
  filePath: string,
  options?: ParseCsvOptions,
): Promise<CsvFileInspectionResult> {
  return walkCsvFile(filePath, options);
}

export async function forEachCsvFileRow(
  filePath: string,
  onRow: (row: ImportRow) => Promise<void> | void,
  options?: ParseCsvOptions,
): Promise<CsvFileInspectionResult> {
  return walkCsvFile(filePath, options, onRow);
}

export async function parseCsvFile(filePath: string, options?: ParseCsvOptions): Promise<ParsedImportUploadResult> {
  const rows: ImportRow[] = [];
  const maxRows = resolveCsvMaterializedMaxRows(options);

  let result;
  try {
    result = await walkCsvFile(filePath, options, (row) => {
      if (rows.length >= maxRows) {
        throw new Error(
          createCsvMaterializationLimitError(maxRows).error
            ?? `CSV import exceeds the in-memory materialization safety limit of ${maxRows.toLocaleString("en-US")} rows.`,
        );
      }
      rows.push(row);
    });
  } catch (error) {
    const message = error instanceof Error ? error.message : "Failed to parse CSV file.";
    if (/in-memory materialization safety limit/i.test(message)) {
      return {
        headers: [],
        rows: [],
        error: message,
      };
    }
    throw error;
  }

  if (result.error) {
    return { headers: [], rows: [], error: result.error };
  }

  return { headers: result.headers, rows };
}

import { promises as fs } from "node:fs";
import type { ParsedImportUploadResult } from "./import-upload-types";

const SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN = /\.(csv|xlsx|xls|xlsb)$/i;
export const IMPORT_UPLOAD_TOO_LARGE_MESSAGE = "The selected file is too large to import. Please split it into smaller files and try again.";

export function isFileAccessError(error: unknown) {
  const code =
    typeof error === "object" && error && "code" in error
      ? String((error as { code?: unknown }).code || "")
      : "";
  return ["ENOENT", "EACCES", "EPERM", "EBUSY"].includes(code);
}

export function createUploadFileAccessError(): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: "Cannot access the uploaded file. Please try again.",
  };
}

export function createUploadFileTooLargeError(): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: IMPORT_UPLOAD_TOO_LARGE_MESSAGE,
  };
}

export async function validateUploadFileSize(
  filePath: string,
  maxBytes?: number,
): Promise<ParsedImportUploadResult | null> {
  if (!Number.isFinite(maxBytes) || (maxBytes as number) <= 0) {
    return null;
  }

  let stats;
  try {
    stats = await fs.stat(filePath);
  } catch (error) {
    if (isFileAccessError(error)) {
      return createUploadFileAccessError();
    }
    throw error;
  }

  return stats.size > (maxBytes as number)
    ? createUploadFileTooLargeError()
    : null;
}

export function isSupportedSpreadsheet(filename: string) {
  return SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN.test(filename);
}

export function stripImportUploadExtension(filename: string) {
  return filename.replace(SUPPORTED_IMPORT_UPLOAD_EXTENSION_PATTERN, "");
}

import fs from "node:fs";
import * as xlsx from "xlsx";
import {
  createUploadFileAccessError,
  createUploadFileTooLargeError,
  isFileAccessError,
  validateUploadFileSize,
} from "./import-upload-file-utils";
import type { ImportRow, ParsedImportUploadResult } from "./import-upload-types";

type ParseExcelOptions = {
  maxRows?: number;
  maxBytes?: number;
};

function mapExcelReadError(error: unknown): ParsedImportUploadResult {
  const message = error instanceof Error ? error.message : "Failed to read Excel file";
  if (message.includes("password") || message.includes("encrypt")) {
    return { headers: [], rows: [], error: "File is password protected" };
  }
  if (message.includes("Unsupported") || message.includes("corrupt")) {
    return { headers: [], rows: [], error: "File is corrupted or unsupported format" };
  }
  return { headers: [], rows: [], error: message };
}

function resolveExcelMaxRows(options?: ParseExcelOptions) {
  const value = options?.maxRows;
  if (value == null || !Number.isFinite(value)) {
    return Number.POSITIVE_INFINITY;
  }

  return Math.max(1, Math.trunc(value));
}

function createSpreadsheetRowLimitError(maxRows: number): ParsedImportUploadResult {
  return {
    headers: [],
    rows: [],
    error: `Spreadsheet import exceeds the configured row limit of ${maxRows.toLocaleString("en-US")} rows. Split the file into smaller uploads.`,
  };
}

function parseWorkbookJsonData(jsonData: unknown[][], options?: ParseExcelOptions): ParsedImportUploadResult {
  if (jsonData.length === 0) {
    return { headers: [], rows: [], error: "Excel file is empty." };
  }

  let headerRowIndex = 0;
  let maxNonEmptyCols = 0;

  for (let index = 0; index < Math.min(5, jsonData.length); index += 1) {
    const row = jsonData[index];
    const nonEmptyCount = row.filter((cell) => cell !== "" && cell !== null && cell !== undefined).length;
    if (nonEmptyCount > maxNonEmptyCols) {
      maxNonEmptyCols = nonEmptyCount;
      headerRowIndex = index;
    }
  }

  const headers = jsonData[headerRowIndex].map((header, index) => {
    const value = String(header || "").trim();
    return value || `Column_${index + 1}`;
  });

  const rows: ImportRow[] = [];
  const maxRows = resolveExcelMaxRows(options);

  for (let rowIndex = headerRowIndex + 1; rowIndex < jsonData.length; rowIndex += 1) {
    const rowData = jsonData[rowIndex];
    const hasAnyData = rowData.some((cell, index) => {
      if (index >= headers.length) return false;
      return String(cell ?? "").trim() !== "";
    });

    if (!hasAnyData) continue;
    if (rows.length >= maxRows) {
      return createSpreadsheetRowLimitError(maxRows);
    }

    const row: ImportRow = {};
    headers.forEach((header, index) => {
      const cellValue = rowData[index];
      row[header] =
        cellValue instanceof Date
          ? cellValue.toLocaleDateString("en-MY")
          : String(cellValue ?? "").trim();
    });
    rows.push(row);
  }

  return { headers, rows };
}

export function parseExcelBuffer(buffer: Buffer, options?: ParseExcelOptions): ParsedImportUploadResult {
  if (Number.isFinite(options?.maxBytes) && (options?.maxBytes as number) > 0 && buffer.length > (options?.maxBytes as number)) {
    return createUploadFileTooLargeError();
  }

  let workbook;
  try {
    workbook = xlsx.read(buffer, {
      type: "buffer",
      cellDates: true,
      cellNF: false,
      cellText: false,
    });
  } catch (error: unknown) {
    return mapExcelReadError(error);
  }

  const firstSheetName = workbook.SheetNames[0];
  if (!firstSheetName) {
    return { headers: [], rows: [], error: "Excel file does not have any sheets." };
  }

  const worksheet = workbook.Sheets[firstSheetName];
  const jsonData = xlsx.utils.sheet_to_json(worksheet, {
    header: 1,
    defval: "",
    raw: false,
  }) as unknown[][];

  (workbook as { SheetNames?: unknown; Sheets?: unknown }).SheetNames = null;
  (workbook as { SheetNames?: unknown; Sheets?: unknown }).Sheets = null;
  workbook = null as never;

  return parseWorkbookJsonData(jsonData, options);
}

export async function parseExcelFile(
  filePath: string,
  options?: ParseExcelOptions,
): Promise<ParsedImportUploadResult> {
  const sizeValidation = await validateUploadFileSize(filePath, options?.maxBytes);
  if (sizeValidation) {
    return sizeValidation;
  }

  let buffer: Buffer;
  try {
    buffer = await fs.promises.readFile(filePath);
  } catch (error) {
    if (isFileAccessError(error)) {
      return createUploadFileAccessError();
    }
    const message = error instanceof Error ? error.message : "Failed to read Excel file";
    return { headers: [], rows: [], error: message };
  }

  return parseExcelBuffer(buffer, options);
}

import type { NextFunction, Request, Response } from "express";
import { ERROR_CODES } from "../../shared/error-codes";
import { HttpError } from "../http/errors";
import { sanitizeRequestId } from "../http/request-id";
import { wasRouteErrorLogged } from "../http/route-observability";
import { logger } from "../lib/logger";

type ErrorLike = {
  message?: string;
  code?: string;
  type?: string;
  status?: number;
  statusCode?: number;
};

type ApiErrorResponse = {
  ok: false;
  message: string;
  requestId?: string;
  error?: {
    code?: string;
    message: string;
    details?: unknown;
  };
};

function readCorrelationRequestId(req: Request, res: Response): string | undefined {
  const responseRequestId = typeof res.getHeader === "function"
    ? sanitizeRequestId(res.getHeader("x-request-id"))
    : "";
  if (responseRequestId) {
    return responseRequestId;
  }

  const requestHeader = req.headers ? sanitizeRequestId(req.headers["x-request-id"]) : "";
  return requestHeader || undefined;
}

function buildApiErrorResponse(
  message: string,
  options?: {
    code?: string | undefined;
    details?: unknown;
    includeError?: boolean | undefined;
    requestId?: string | undefined;
  },
): ApiErrorResponse {
  const includeError = options?.includeError || Boolean(options?.code || options?.details !== undefined);

  return {
    ok: false,
    message,
    ...(options?.requestId ? { requestId: options.requestId } : {}),
    ...(includeError
      ? {
          error: {
            ...(options?.code ? { code: options.code } : {}),
            message,
            ...(options?.details !== undefined ? { details: options.details } : {}),
          },
        }
      : {}),
  };
}

export function errorHandler(err: unknown, req: Request, res: Response, next: NextFunction) {
  if (res.headersSent) {
    return next(err);
  }

  const error = err as ErrorLike;
  const requestId = readCorrelationRequestId(req, res);

  if (error?.type === "entity.too.large" || error?.status === 413 || error?.statusCode === 413) {
    return res.status(413).json(buildApiErrorResponse("The request payload is too large to process.", {
      code: ERROR_CODES.PAYLOAD_TOO_LARGE,
      includeError: true,
      requestId,
    }));
  }

  if (err instanceof HttpError) {
    if (!err.expose) {
      if (!wasRouteErrorLogged(err)) {
        logger.error("Unhandled API HttpError", {
          path: req.path,
          method: req.method,
          requestId,
          code: err.code,
          statusCode: err.statusCode,
          message: err.message,
        });
      }

      return res.status(err.statusCode).json(buildApiErrorResponse("Internal server error", {
        requestId,
      }));
    }

    return res.status(err.statusCode).json(buildApiErrorResponse(err.message, {
      requestId,
      ...(err.code ? { code: err.code } : {}),
      ...(err.details !== undefined ? { details: err.details } : {}),
    }));
  }

  if (!wasRouteErrorLogged(err)) {
    logger.error("Unhandled API error", {
      path: req.path,
      method: req.method,
      requestId,
      code: error?.code,
      message: error?.message,
    });
  }

  return res.status(500).json(buildApiErrorResponse("Internal server error", {
    requestId,
  }));
}

import { randomUUID } from "node:crypto";

const REQUEST_ID_MAX_LENGTH = 128;
const REQUEST_ID_SAFE_CHAR_PATTERN = /[A-Za-z0-9._:-]/g;

export function sanitizeRequestId(rawRequestId: unknown): string {
  const raw = String(rawRequestId || "").trim();
  if (!raw) {
    return "";
  }

  const safeCharacters = raw.match(REQUEST_ID_SAFE_CHAR_PATTERN)?.join("") || "";
  return safeCharacters.slice(0, REQUEST_ID_MAX_LENGTH);
}

export function resolveRequestId(rawRequestId: unknown): string {
  return sanitizeRequestId(rawRequestId) || randomUUID();
}

import type { NextFunction, Request, RequestHandler, Response } from "express";
import { logger } from "../lib/logger";

const ROUTE_ERROR_LOGGED_SYMBOL = Symbol.for("sqr.routeErrorLogged");

type RouteHandler = (
  req: Request,
  res: Response,
  next: NextFunction,
) => unknown | Promise<unknown>;

type RouteErrorLike = Error & {
  [ROUTE_ERROR_LOGGED_SYMBOL]?: true;
};

type RouteLoggerOptions = {
  message?: string | undefined;
};

function readRoutePath(req: Request) {
  const routePath = req.route?.path;
  return typeof routePath === "string"
    ? routePath
    : Array.isArray(routePath)
      ? routePath.join(",")
      : undefined;
}

export function markRouteErrorLogged(error: unknown) {
  if (!error || typeof error !== "object") {
    return;
  }

  Object.defineProperty(error, ROUTE_ERROR_LOGGED_SYMBOL, {
    configurable: true,
    enumerable: false,
    value: true,
    writable: true,
  });
}

export function wasRouteErrorLogged(error: unknown): boolean {
  return Boolean(
    error &&
    typeof error === "object" &&
    (error as RouteErrorLike)[ROUTE_ERROR_LOGGED_SYMBOL] === true,
  );
}

export function logRouteHandlerError(
  error: unknown,
  req: Request,
  options?: RouteLoggerOptions,
) {
  if (wasRouteErrorLogged(error)) {
    return;
  }

  logger.error(options?.message || "Unhandled route handler error", {
    error,
    method: req.method,
    path: req.path,
    originalUrl: req.originalUrl,
    baseUrl: req.baseUrl || undefined,
    routePath: readRoutePath(req),
    username: (req as { user?: { username?: string | undefined } }).user?.username || undefined,
  });

  markRouteErrorLogged(error);
}

export function routeHandler(
  handler: RouteHandler,
  options?: RouteLoggerOptions,
): RequestHandler {
  return (req, res, next) => {
    void Promise.resolve(handler(req, res, next)).catch((error) => {
      logRouteHandlerError(error, req, options);
      next(error);
    });
  };
}

