import { ensureObject } from "../http/validation";
import { jsonObjectSchema } from "../../shared/json-schema";
import type {
  CreateImportBody,
  ImportDataPageCursor,
  NormalizeImportRowResult,
  RenameImportBody,
} from "./imports-service-types";

export function encodeImportDataPageCursor(cursor: ImportDataPageCursor): string {
  return Buffer.from(JSON.stringify(cursor), "utf8").toString("base64url");
}

export function parseImportDataPageCursor(
  rawCursor: string | null | undefined,
): ImportDataPageCursor | null {
  const normalized = String(rawCursor || "").trim();
  if (!normalized) {
    return null;
  }

  try {
    const parsed = JSON.parse(
      Buffer.from(normalized, "base64url").toString("utf8"),
    ) as Partial<ImportDataPageCursor>;
    const lastRowId = String(parsed.lastRowId || "").trim();
    const page = Number.isFinite(Number(parsed.page)) ? Math.trunc(Number(parsed.page)) : 0;
    if (!lastRowId || page < 2) {
      return null;
    }

    return {
      lastRowId,
      page,
    };
  } catch {
    return null;
  }
}

export function parseCreateImportBody(bodyRaw: unknown): CreateImportBody {
  const body = ensureObject(bodyRaw) || {};
  const name = String(body.name ?? "");
  const filename = String(body.filename ?? "");
  const dataRows = Array.isArray(body.rows) ? body.rows : (Array.isArray(body.data) ? body.data : []);

  return {
    name,
    filename,
    dataRows,
  };
}

export function parseRenameBody(bodyRaw: unknown): RenameImportBody {
  const body = ensureObject(bodyRaw) || {};
  return {
    name: String(body.name ?? ""),
  };
}

export function normalizeImportRow(row: unknown): NormalizeImportRowResult {
  const normalized = ensureObject(row);
  if (!normalized) {
    throw new Error("Invalid jsonDataJsonb");
  }

  const parsed = jsonObjectSchema.safeParse(normalized);
  if (!parsed.success) {
    throw new Error("Invalid jsonDataJsonb");
  }

  return parsed.data;
}

import type {
  CreateImportFromCsvFileInput,
  CreateImportInput,
  ImportsServiceStorage,
} from "./imports-service-types";
import { runtimeConfig } from "../config/runtime";
import { forEachCsvFileRow } from "./import-upload-csv-utils";
import { normalizeImportRow } from "./imports-service-parsers";

const IMPORT_INSERT_CHUNK_SIZE = 20;

export class ImportsServiceMutationOperations {
  constructor(private readonly storage: ImportsServiceStorage) {}

  async createImport(params: CreateImportInput) {
    const importRecord = await this.storage.createImport({
      name: params.name,
      filename: params.filename,
      ...(params.createdBy ? { createdBy: params.createdBy } : {}),
    });

    for (let index = 0; index < params.dataRows.length; index += IMPORT_INSERT_CHUNK_SIZE) {
      const chunk = params.dataRows.slice(index, index + IMPORT_INSERT_CHUNK_SIZE);
      await Promise.all(
        chunk.map((row) =>
          this.storage.createDataRow({
            importId: importRecord.id,
            jsonDataJsonb: normalizeImportRow(row),
          }),
        ),
      );
    }

    if (params.createdBy) {
      await this.storage.createAuditLog({
        action: "IMPORT_DATA",
        performedBy: params.createdBy,
        targetResource: params.name,
        details: `Imported ${params.dataRows.length} rows from ${params.filename}`,
      });
    }

    return importRecord;
  }

  async createImportFromCsvFile(params: CreateImportFromCsvFileInput) {
    const importRecord = await this.storage.createImport({
      name: params.name,
      filename: params.filename,
      ...(params.createdBy ? { createdBy: params.createdBy } : {}),
    });

    let pendingRows: unknown[] = [];
    const flushPendingRows = async () => {
      if (pendingRows.length === 0) {
        return;
      }

      const chunk = pendingRows;
      pendingRows = [];
      await Promise.all(
        chunk.map((row) =>
          this.storage.createDataRow({
            importId: importRecord.id,
            jsonDataJsonb: normalizeImportRow(row),
          }),
        ),
      );
    };

    let parsed: Awaited<ReturnType<typeof forEachCsvFileRow>>;
    try {
      parsed = await forEachCsvFileRow(
        params.filePath,
        async (row) => {
          pendingRows.push(row);
          if (pendingRows.length >= IMPORT_INSERT_CHUNK_SIZE) {
            await flushPendingRows();
          }
        },
        { maxRows: runtimeConfig.runtime.importCsvMaxRows },
      );

      if (parsed.error) {
        throw new Error(parsed.error);
      }

      await flushPendingRows();
    } catch (error) {
      await this.storage.deleteDataRowsByImport(importRecord.id);
      await this.storage.deleteImport(importRecord.id);
      throw error;
    }

    if (parsed.rowCount <= 0) {
      await this.storage.deleteDataRowsByImport(importRecord.id);
      await this.storage.deleteImport(importRecord.id);
      throw new Error("No data rows provided");
    }

    if (params.createdBy) {
      await this.storage.createAuditLog({
        action: "IMPORT_DATA",
        performedBy: params.createdBy,
        targetResource: params.name,
        details: `Imported ${parsed.rowCount} rows from ${params.filename}`,
      });
    }

    return importRecord;
  }

  async renameImport(importId: string, name: string, updatedBy?: string) {
    const updated = await this.storage.updateImportName(importId, name);
    if (!updated) {
      return null;
    }

    if (updatedBy) {
      await this.storage.createAuditLog({
        action: "UPDATE_IMPORT",
        performedBy: updatedBy,
        targetResource: name,
      });
    }

    return updated;
  }

  async deleteImport(importId: string, deletedBy?: string) {
    const importRecord = await this.storage.getImportById(importId);
    const deleted = await this.storage.deleteImport(importId);
    if (!deleted) {
      return false;
    }

    if (deletedBy) {
      await this.storage.createAuditLog({
        action: "DELETE_IMPORT",
        performedBy: deletedBy,
        targetResource: importRecord?.name || importId,
      });
    }

    return true;
  }
}

import type {
  AnalyzeAllImportsResult,
  AnalyzeImportResult,
  ImportDataPageInput,
  ImportDataPageResult,
  ImportDetailsResult,
  ImportsServiceAnalysis,
  ImportsServiceRepository,
  ImportsServiceStorage,
  ListImportsInput,
  SearchDataRowsResult,
  SearchImportRowsInput,
} from "./imports-service-types";
import { encodeImportDataPageCursor, parseImportDataPageCursor } from "./imports-service-parsers";

export class ImportsServiceReadOperations {
  constructor(
    private readonly storage: ImportsServiceStorage,
    private readonly importsRepository: ImportsServiceRepository,
    private readonly importAnalysisService: ImportsServiceAnalysis,
  ) {}

  async searchImportRows(params: SearchImportRowsInput): Promise<SearchDataRowsResult> {
    return this.storage.searchDataRows({
      importId: params.importId,
      search: params.search ?? "",
      limit: params.limit,
      offset: params.offset,
      columnFilters: params.columnFilters ?? [],
      cursor: params.cursor ?? null,
    });
  }

  async listImports(params: ListImportsInput = {}) {
    return this.importsRepository.listImportsWithRowCountsPage(params);
  }

  async getImportDetails(importId: string): Promise<ImportDetailsResult | null> {
    const importRecord = await this.storage.getImportById(importId);
    if (!importRecord) {
      return null;
    }

    const rows = await this.storage.getDataRowsByImport(importId);
    return {
      import: importRecord,
      rows,
    };
  }

  async getImportDataPage(params: ImportDataPageInput): Promise<ImportDataPageResult> {
    const maxLimit = Math.min(params.isDbProtected ? 120 : 500, params.viewerRowsPerPage);
    const limit = Math.max(10, Math.min(params.requestedLimit, maxLimit));
    const parsedCursor = parseImportDataPageCursor(params.cursor);
    if (params.cursor && !parsedCursor) {
      throw new Error("Invalid import data cursor.");
    }

    const effectivePage = parsedCursor?.page ?? params.page;
    const offset = parsedCursor ? 0 : (params.page - 1) * limit;
    const search = String(params.search || "").trim();
    const [result, headers] = await Promise.all([
      this.storage.searchDataRows({
        importId: params.importId,
        search: search || null,
        limit,
        offset,
        columnFilters: params.columnFilters ?? [],
        cursor: parsedCursor?.lastRowId ?? null,
      }),
      this.importsRepository.getImportColumnNames(params.importId),
    ]);

    const nextCursor = result.nextCursorRowId
      ? encodeImportDataPageCursor({
          lastRowId: result.nextCursorRowId,
          page: effectivePage + 1,
        })
      : null;
    const logicalOffset = Math.max(0, (effectivePage - 1) * limit);
    const total = result.total || 0;
    const totalPages = Math.max(1, Math.ceil(total / limit));
    const resolvedHeaders = headers.length > 0
      ? headers
      : Array.from(
          new Set(
            (result.rows || []).flatMap((row) => {
              const record = row?.jsonDataJsonb;
              if (!record || typeof record !== "object" || Array.isArray(record)) {
                return [];
              }

              return Object.keys(record as Record<string, unknown>)
                .map((key) => String(key || "").trim())
                .filter(Boolean);
            }),
          ),
        );

    return {
      rows: (result.rows || []).map((row) => ({
        id: row.id,
        importId: row.importId,
        jsonDataJsonb: row.jsonDataJsonb,
      })),
      headers: resolvedHeaders,
      total: result.total || 0,
      page: effectivePage,
      limit,
      pageSize: limit,
      offset: logicalOffset,
      nextCursor,
      pagination: {
        mode: "hybrid",
        page: effectivePage,
        pageSize: limit,
        limit,
        offset: logicalOffset,
        total,
        totalPages,
        nextCursor,
        hasNextPage: nextCursor !== null,
        hasPreviousPage: effectivePage > 1,
      },
    };
  }

  async analyzeImport(importId: string, signal?: AbortSignal): Promise<AnalyzeImportResult | null> {
    const importRecord = await this.storage.getImportById(importId);
    if (!importRecord) {
      return null;
    }

    return this.importAnalysisService.analyzeImport(importRecord, signal);
  }

  async analyzeAll(signal?: AbortSignal): Promise<AnalyzeAllImportsResult> {
    const imports = await this.importsRepository.getImportsWithRowCounts();
    return this.importAnalysisService.analyzeAll(imports, signal);
  }
}

